// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.math.BigDecimal;

import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.base.CoreDatatype;
import org.eclipse.rdf4j.model.util.Values;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Low-level proof for the native expression codec: stored literals must expose datatype and lexical/numeric payloads
 * without creating {@link Literal} objects.
 */
public class ValueStoreNativeValueCodecTest {

	private ValueStore valueStore;

	@BeforeEach
	public void before(@TempDir File dataDir) throws Exception {
		this.valueStore = new ValueStore(new File(dataDir, "values"), new LmdbStoreConfig());
	}

	@AfterEach
	public void after() throws Exception {
		valueStore.close();
	}

	@Test
	public void decodesStoredIntegerLiteralMetadataWithoutLiteralObject() throws Exception {
		Literal literal = Values.literal("00121", XSD.INTEGER);
		valueStore.startTransaction(true);
		long id = valueStore.storeValue(literal);
		valueStore.commit();

		LmdbNativeValueCodec.DecodedValue decoded = new LmdbNativeValueCodec(valueStore).decode(id);

		assertThat(ValueIds.isInlined(id)).isFalse();
		assertThat(decoded.literal()).isTrue();
		assertThat(decoded.coreDatatype()).isEqualTo(CoreDatatype.XSD.INTEGER);
		assertThat(decoded.label()).isEqualTo("00121");
		assertThat(decoded.decimalValue()).isEqualByComparingTo(BigDecimal.valueOf(121));
	}

	@Test
	public void decodesInlinedAndStoredStringsWithTheSameApi() throws Exception {
		Literal shortLiteral = Values.literal("alpha");
		Literal storedLiteral = Values.literal("Alphabetical stored literal");
		valueStore.startTransaction(true);
		long shortId = valueStore.storeValue(shortLiteral);
		long storedId = valueStore.storeValue(storedLiteral);
		valueStore.commit();

		LmdbNativeValueCodec codec = new LmdbNativeValueCodec(valueStore);

		assertThat(ValueIds.isInlined(shortId)).isTrue();
		assertThat(ValueIds.isInlined(storedId)).isFalse();
		assertThat(codec.decode(shortId).label()).isEqualTo("alpha");
		assertThat(codec.decode(storedId).label()).isEqualTo("Alphabetical stored literal");
	}
}
